func TestSearchQuotesFTSQuerySyntax(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "ip", "value": "10.0.0.1"}`),
		json.RawMessage(`{"id": "cidr", "value": "172.16.192.0/18"}`),
		json.RawMessage(`{"id": "host", "value": "host.example.com"}`),
		json.RawMessage(`{"id": "email", "value": "user@example.com"}`),
		json.RawMessage(`{"id": "mac", "value": "aa:bb:cc:dd:ee:ff"}`),
		json.RawMessage(`{"id": "hyphen", "value": "some-name"}`),
		json.RawMessage(`{"id": "multi", "value": "error with extra words before timeout"}`),
	}
	if stored, failed, err := s.UpsertBatch("search-regression", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	} else if failed != 0 || stored != len(items) {
		t.Fatalf("UpsertBatch stored=%d failed=%d, want stored=%d failed=0", stored, failed, len(items))
	}

	for _, query := range []string{
		"10.0.0.1",
		"172.16.192.0/18",
		"host.example.com",
		"user@example.com",
		"aa:bb:cc:dd:ee:ff",
		"some-name",
		"error timeout",
	} {
		results, err := s.Search(query, 10)
		if err != nil {
			t.Fatalf("Search(%q): %v", query, err)
		}
		if len(results) == 0 {
			t.Fatalf("Search(%q) returned no results", query)
		}
	}
}

// TestUpsertBatch_PopulatesConfigSchemaTable verifies that UpsertBatch
// dispatches paginated items into both the generic resources table AND the
// typed config_schema table. Regression for issue #268: before the fix, paginated
// syncs only filled the generic resources table, so domain commands that
// query the typed table saw zero rows.
func TestUpsertBatch_PopulatesConfigSchemaTable(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "test-001", "adapters_id": "test-parent-001"}`),
		json.RawMessage(`{"id": "test-002", "adapters_id": "test-parent-001"}`),
		json.RawMessage(`{"id": "test-003", "adapters_id": "test-parent-001"}`),
	}
	if _, _, err := s.UpsertBatch("config_schema", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "config_schema").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "config_schema")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count config_schema: %v", err)
	}
	if typed != len(items) {
		t.Fatalf("config_schema count = %d, want %d (typed table not populated by UpsertBatch)", typed, len(items))
	}
}

// TestUpsertBatch_TypedFailureDoesNotStrandConfigSchemaGeneric exercises
// the savepoint isolation around the typed-table dispatch. The fixture omits
// the NOT NULL parent FK column so the typed insert fails; the savepoint
// rolls back only the typed projection. The generic resources row inserted
// just before must survive. Regression for issue #1392, where a single
// outer transaction caused typed-table failures to cascade and silently
// discard every successfully fetched API row.
func TestUpsertBatch_TypedFailureDoesNotStrandConfigSchemaGeneric(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	// Items deliberately omit "adapters_id" so the typed NOT NULL
	// constraint fires.
	items := []json.RawMessage{
		json.RawMessage(`{"id": "orphan-001"}`),
		json.RawMessage(`{"id": "orphan-002"}`),
		json.RawMessage(`{"id": "orphan-003"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("config_schema", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v (typed-table failure must not propagate)", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d (generic resources rows must land even when typed table fails)", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "config_schema").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (savepoint rollback must not undo generic insert)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "config_schema")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count config_schema: %v", err)
	}
	if typed != 0 {
		t.Fatalf("config_schema count = %d, want 0 (typed insert violated NOT NULL on %q)", typed, "adapters_id")
	}
}

// TestUpsertBatch_KeysConfigSchemaByChildAndParent verifies dependent
// sub-collection rows with the same child id but different parent ids do not
// overwrite one another in either the generic resources table or the typed
// table. Regression for issue #2471.
func TestUpsertBatch_KeysConfigSchemaByChildAndParent(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id": "shared_child", "adapters_id": "parent_A"}`),
		json.RawMessage(`{"id": "shared", "adapters_id": "child_parent_A"}`),
		json.RawMessage(`{"id": "shared_child", "adapters_id": "parent_B"}`),
		json.RawMessage(`{"id": "other_child", "adapters_id": "parent_A"}`),
	}
	stored, extractFailures, err := s.UpsertBatch("config_schema", items)
	if err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}
	if stored != len(items) {
		t.Fatalf("stored = %d, want %d", stored, len(items))
	}
	if extractFailures != 0 {
		t.Fatalf("extractFailures = %d, want 0", extractFailures)
	}

	db := s.DB()

	var generic int
	if err := db.QueryRow(`SELECT COUNT(*) FROM resources WHERE resource_type = ?`, "config_schema").Scan(&generic); err != nil {
		t.Fatalf("count resources: %v", err)
	}
	if generic != len(items) {
		t.Fatalf("resources count = %d, want %d (dependent rows collapsed on child id)", generic, len(items))
	}

	var typed int
	typedQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, "config_schema")
	if err := db.QueryRow(typedQuery).Scan(&typed); err != nil {
		t.Fatalf("count config_schema: %v", err)
	}
	if typed != len(items) {
		t.Fatalf("config_schema count = %d, want %d (typed rows collapsed on child id)", typed, len(items))
	}

	var parentMatches int
	parentQuery := fmt.Sprintf(`SELECT COUNT(*) FROM "%s" WHERE "adapters_id" = ?`, "config_schema")
	if err := db.QueryRow(parentQuery, "parent_A").Scan(&parentMatches); err != nil {
		t.Fatalf("count by adapters_id: %v", err)
	}
	if parentMatches != 2 {
		t.Fatalf("adapters_id=parent_A count = %d, want 2", parentMatches)
	}
}

